body:
This JSX:

```jsx
import * as React from 'react';
import { Toggle } from '@base-ui-components/react/toggle';
import styles from './index.module.css';

export default function ExampleToggle() {
  return (
    <div className={styles.Panel}>
      <Toggle
        aria-label="Favorite"
        render={(props, state) => {
          if (state.pressed) {
            return (
              <button type="button" className={styles.Button} {...props}>
                <HeartFilledIcon className={styles.Icon} />
              </button>
            );
          }

          return (
            <button type="button" className={styles.Button} {...props}>
              <HeartOutlineIcon className={styles.Icon} />
            </button>
          );
        }}
      />
    </div>
  );
}
```

produces the following DOM:

<img width="814" alt="image" src="https://github.com/user-attachments/assets/4565ed74-6d50-425c-9600-939850700efd">

CSS class is missing.

Haven't tested other components.

